class Playground {
    async run(inputs) {
        let numsArr;
        try {
            numsArr = JSON.parse(inputs[0]);
            if (!Array.isArray(numsArr)) throw new Error();
        } catch (e) {
            this.log("Invalid input. Please provide a valid array like [1, 2, 3]");
            return [];
        }

        // Initialize slots
        this.nums.init(numsArr);
        this.current.init([]);
        this.used.init([]);
        this.recursionTree.init();
        this.callstack.init();

        const results = [];
        this.nodeCounter = 0;
        this.numsSize = numsArr.length;

        await this.backtrack(results);

        this.log(`Found ${results.length} total permutations.`);
        return results;
    }

    async backtrack(results) {
        const path = this.current.getValues();
        const nodeId = "node_" + (this.nodeCounter++);
        const label = path.length === 0 ? "root" : "[" + path.join(",") + "]";

        // Recursion Visualization Start
        this.callstack.pushFrame("backtrack", { path: [...path] });
        this.recursionTree.enterNode(nodeId, label);
        this.log(`Exploring path: ${label}`);
        await this.await();

        // Base Case
        if (path.length === this.numsSize) {
            results.push([...path]);
            this.log(`Found valid permutation: [${path.join(",")}]`);
            await this.await();

            this.callstack.popFrame();
            this.recursionTree.exitNode("#00f5a0"); // Success color
            return;
        }

        // Recursive Step
        for (let i = 0; i < this.numsSize; i++) {
            this.callstack.updateLocal("i", i);
            const val = this.nums.get(i);

            if (this.used.has(val)) {
                this.log(`Value ${val} is already used in current path. Skipping.`);
                this.nums.highlight(i, "#ff4d4f");
                await this.await();
                this.nums.highlight(i, null);
                continue;
            }

            // Choose
            this.log(`Choosing ${val} at index ${i}`);
            this.nums.highlight(i, "#00e0ff");
            this.used.add(val);
            this.current.push(val);
            await this.await();

            // Recurse
            await this.backtrack(results);

            // Un-choose (Backtrack)
            this.log(`Backtracking: removing ${val} from path.`);
            this.current.pop();
            this.used.remove(val);
            this.nums.highlight(i, null);
            await this.await();
        }

        // Recursion Visualization End
        this.callstack.popFrame();
        this.recursionTree.exitNode();
    }
}
